// Parse and validate agent request
const input = $input.first().json;

// Handle both webhook and manual trigger
let request = input.body || input;

// For testing, provide defaults
if (!request.agent) {
  request = {
    agent: {
      id: 'claude-code-v1',
      provider: 'anthropic',
      model: 'claude-3-5-sonnet-20241022',
      system_prompt: 'You are a helpful AI assistant that can read files, execute commands, and help with development tasks. When you need to use a tool, respond with a JSON object containing "action" and "input" fields. When the task is complete, include "TASK_COMPLETE" in your response.',
      tools_available: ['file_read', 'file_write', 'command', 'web_fetch', 'git_status']
    },
    task: {
      objective: 'Read the CLAUDE.md file and summarize it',
      context: '/Users/williammarceaujr./dev-sandbox'
    },
    config: {
      max_iterations: 20,
      require_approval_for: ['file_delete', 'git_push --force'],
      notification_channel: 'telegram'
    }
  };
}

// Validate required fields
if (!request.agent) {
  throw new Error('Missing required field: agent');
}
if (!request.task) {
  throw new Error('Missing required field: task');
}

// Generate session ID if not provided
if (!request.session_id) {
  request.session_id = 'session_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}

// Set default provider
if (!request.agent.provider) {
  request.agent.provider = 'anthropic';
}

// Set default model based on provider
if (!request.agent.model) {
  request.agent.model = request.agent.provider === 'xai' 
    ? 'grok-2-latest' 
    : 'claude-3-5-sonnet-20241022';
}

// Set default config
const defaultConfig = {
  max_iterations: 20,
  iteration_timeout_seconds: 60,
  require_approval_for: ['file_delete', 'git_push --force', 'rm -rf'],
  notify_on: ['completion', 'error'],
  notification_channel: 'telegram'
};
request.config = { ...defaultConfig, ...request.config };

// Initialize state
request.state = {
  iteration: 0,
  status: 'initializing',
  history: [],
  messages: [
    {
      role: 'user',
      content: `Task: ${request.task.objective}\n\nContext: ${request.task.context || 'No specific context'}\n\nConstraints: ${(request.task.constraints || []).join(', ') || 'None'}\n\nAvailable tools: ${request.agent.tools_available.join(', ')}\n\nWhen you need to use a tool, respond with a JSON object like:\n{"action": "file_read", "input": {"path": "/path/to/file"}}\n\nWhen the task is complete, include TASK_COMPLETE in your response.`
    }
  ]
};

return { json: request };

// Prepare API request based on provider
const data = $input.first().json;
const provider = data.agent.provider || 'anthropic';
const model = data.agent.model;
const systemPrompt = data.agent.system_prompt || 'You are a helpful AI assistant.';
const messages = data.state.messages;

let apiConfig = {};

if (provider === 'anthropic') {
  // Anthropic Claude API format
  apiConfig = {
    url: 'https://api.anthropic.com/v1/messages',
    body: {
      model: model,
      max_tokens: 4096,
      system: systemPrompt,
      messages: messages
    },
    headers: {
      'Content-Type': 'application/json',
      'anthropic-version': '2023-06-01'
    }
  };
} else if (provider === 'xai') {
  // xAI Grok API format (OpenAI compatible)
  const xaiMessages = [
    { role: 'system', content: systemPrompt },
    ...messages
  ];
  apiConfig = {
    url: 'https://api.x.ai/v1/chat/completions',
    body: {
      model: model,
      messages: xaiMessages,
      max_tokens: 4096
    },
    headers: {
      'Content-Type': 'application/json'
    }
  };
}

return {
  json: {
    ...data,
    apiConfig: apiConfig
  }
};

// Parse AI response and extract tool call or completion
const input = $input.first().json;
const prevData = $('Prepare API Request').first().json;
const provider = prevData.agent.provider || 'anthropic';

let responseText = '';
let toolCall = null;

// Handle errors
if (input.error) {
  return {
    json: {
      ...prevData,
      action_type: 'error',
      error: input.error.message || 'API call failed',
      continue_loop: false
    }
  };
}

// Parse response based on provider
if (provider === 'anthropic') {
  // Anthropic format: { content: [{ type: 'text', text: '...' }] }
  const content = input.content || [];
  for (const block of content) {
    if (block.type === 'text') {
      responseText = block.text;
    }
  }
} else if (provider === 'xai') {
  // OpenAI format: { choices: [{ message: { content: '...' }}] }
  responseText = input.choices?.[0]?.message?.content || '';
}

// Check for task completion
if (responseText.includes('TASK_COMPLETE')) {
  return {
    json: {
      ...prevData,
      action_type: 'complete',
      result: responseText,
      continue_loop: false
    }
  };
}

// Try to parse tool call from response
try {
  // Look for JSON in the response
  const jsonMatch = responseText.match(/\{[\s\S]*?"action"[\s\S]*?\}/g);
  if (jsonMatch) {
    for (const match of jsonMatch) {
      try {
        const parsed = JSON.parse(match);
        if (parsed.action) {
          toolCall = parsed;
          break;
        }
      } catch (e) {
        continue;
      }
    }
  }
} catch (e) {
  // No valid JSON found
}

if (toolCall) {
  // Add assistant message to history
  prevData.state.messages.push({
    role: 'assistant',
    content: responseText
  });

  return {
    json: {
      ...prevData,
      action_type: toolCall.action,
      action_input: toolCall.input || {},
      raw_response: responseText,
      continue_loop: true
    }
  };
}

// No tool call - might be thinking/clarifying
// Add to messages and continue
prevData.state.messages.push({
  role: 'assistant',
  content: responseText
});

// If no tool call and max iterations, complete
if (prevData.state.iteration >= prevData.config.max_iterations - 1) {
  return {
    json: {
      ...prevData,
      action_type: 'complete',
      result: responseText,
      continue_loop: false
    }
  };
}

return {
  json: {
    ...prevData,
    action_type: 'think',
    thought: responseText,
    continue_loop: true
  }
};

// Map action type to Python Bridge endpoint
const data = $input.first().json;
const action = data.action_type;
const input = data.action_input || {};

const endpoints = {
  'file_read': '/files/read',
  'file_write': '/files/write',
  'file_edit': '/files/edit',
  'file_list': '/files/list',
  'file_delete': '/files/delete',
  'command': '/command/execute',
  'git_status': '/git/status',
  'git_commit': '/git/commit',
  'git_push': '/git/push',
  'git_diff': '/git/diff'
};

const endpoint = endpoints[action] || '/health';

return {
  json: {
    ...data,
    bridge_endpoint: `http://localhost:5010${endpoint}`,
    bridge_body: input
  }
};

// Format tool result as observation for the agent
const toolResult = $input.first().json;
const prevData = $('Parse Tool Request').first().json;

// Format the observation
let observation = '';
if (toolResult.success !== undefined) {
  if (toolResult.success) {
    if (toolResult.content) {
      // File read result
      observation = `File contents:\n${toolResult.content}`;
    } else if (toolResult.stdout !== undefined) {
      // Command result
      observation = `Command executed. Exit code: ${toolResult.exit_code}\nOutput:\n${toolResult.stdout}`;
      if (toolResult.stderr) {
        observation += `\nStderr:\n${toolResult.stderr}`;
      }
    } else if (toolResult.branch !== undefined) {
      // Git status
      observation = `Git status:\nBranch: ${toolResult.branch}\nClean: ${toolResult.clean}\nStaged: ${JSON.stringify(toolResult.staged)}\nUnstaged: ${JSON.stringify(toolResult.unstaged)}`;
    } else {
      observation = `Operation succeeded: ${JSON.stringify(toolResult)}`;
    }
  } else {
    observation = `Error: ${toolResult.error || 'Unknown error'}`;
  }
} else {
  // Web fetch or other response
  observation = `Result: ${JSON.stringify(toolResult).substring(0, 5000)}`;
}

// Add tool result to messages
prevData.state.messages.push({
  role: 'user',
  content: `Tool result for ${prevData.action_type}:\n${observation}`
});

// Increment iteration
prevData.state.iteration += 1;

// Add to history
prevData.state.history.push({
  iteration: prevData.state.iteration,
  action: prevData.action_type,
  input: prevData.action_input,
  result: toolResult.success !== undefined ? toolResult.success : true,
  timestamp: new Date().toISOString()
});

// Check if should continue
const shouldContinue = prevData.state.iteration < prevData.config.max_iterations;

return {
  json: {
    ...prevData,
    last_observation: observation,
    continue_loop: shouldContinue
  }
};

// Prepare final response
const data = $input.first().json;

const response = {
  session_id: data.session_id,
  agent_id: data.agent.id,
  provider: data.agent.provider,
  status: data.action_type === 'error' ? 'failed' : 'completed',
  iterations: data.state.iteration,
  result: data.result || data.error || 'Task completed',
  history: data.state.history
};

return { json: response };

// Increment iteration for think action (no tool call)
const data = $input.first().json;
data.state.iteration += 1;

// Check if should continue
const shouldContinue = data.state.iteration < data.config.max_iterations;

return {
  json: {
    ...data,
    continue_loop: shouldContinue
  }
};

